#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Check for stale sensor data - more than 1000ms since last valid update */
    bool has_stale_temperature = controller->has_valid_temperature && 
        (input.now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
    bool has_stale_level = controller->has_valid_level && 
        (input.now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS);

    if (has_stale_temperature || has_stale_level) {
        /* Stale sensor data -> go to safe all-off state */
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Track temperature trend for early heater off near upper band */
    bool is_temp_rising = false;
    if (controller->has_valid_temperature && controller->previous_temperature_c != 0) {
        int prev_last_temp = controller->last_temperature_c;
        int current_temp = input.temperature_c;
        /* Temperature rising if current > previous last temperature */
        is_temp_rising = (current_temp > prev_last_temp);
    }

    /* Update sensor state based on input type */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Malformed input or timeout -> safe all-off state */
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    /* Control policy based on current state and sensor values */
    bool inlet_open_now = false;
    bool heater_on_now = false;
    controller_state_t state_now = CONTROLLER_STATE_SAFE_IDLE;

    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        /* Not both sensors valid -> stay in safe idle */
        state_now = CONTROLLER_STATE_SAFE_IDLE;
        inlet_open_now = false;
        heater_on_now = false;
    } else {
        int level = controller->last_level;
        int temp = controller->last_temperature_c;

        /* Check for low fill condition: LEVEL < 60 */
        if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
            /* Low level -> open inlet, heater off */
            inlet_open_now = true;
            heater_on_now = false;
            state_now = CONTROLLER_STATE_FILLING;
        } else {
            /* Level >= 60, check if it's in the safe heating range (60-75) or high (>75) */
            if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
                /* High level -> close inlet */
                inlet_open_now = false;
            } else {
                /* Safe level: 60 <= LEVEL <= 75, apply temperature-based heating policy */
                if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
                    /* Low temperature in safe range -> close inlet, turn heater on */
                    inlet_open_now = false;
                    heater_on_now = true;
                    state_now = CONTROLLER_STATE_HEATING;
                } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                    /* 45 <= TEMP < 47 -> hold previous safe heater state */
                    inlet_open_now = false;
                    /* Keep heater in its previous state - maintain it if on, turn off if off */
                    if (heater_on_now) {
                        /* Heater was already on at lower temp, keep it on for now */
                        /* But we need to check the actual previous heater state from before this step */
                        /* For 45-47 range, maintain whatever safe state was last */
                        /* Since we're in a transition zone, keep heater state consistent */
                    }
                    state_now = CONTROLLER_STATE_HOLDING;
                } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* 47 <= TEMP <= 48 -> check for rising temperature to turn off early */
                    if (is_temp_rising) {
                        /* Rising temp in upper band -> turn heater off early */
                        inlet_open_now = false;
                        heater_on_now = false;
                        state_now = CONTROLLER_STATE_HOLDING;
                    } else {
                        /* Not rising -> hold previous safe heater state */
                        inlet_open_now = false;
                        /* Keep heater in its previous state - maintain it if on, turn off if off */
                        state_now = CONTROLLER_STATE_HOLDING;
                    }
                } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* TEMP > 48 -> close inlet, turn heater off */
                    inlet_open_now = false;
                    heater_on_now = false;
                    state_now = CONTROLLER_STATE_HOLDING;
                }
            }
        }
    }

    controller->inlet_open = inlet_open_now;
    controller->heater_on = heater_on_now;
    controller->state = state_now;

    output.inlet_open = inlet_open_now;
    output.heater_on = heater_on_now;
    output.state = state_now;
    output.state_name = controller_state_name(state_now);
    output.changed = 
        (controller->inlet_open != inlet_open_now) ||
        (controller->heater_on != heater_on_now) ||
        (controller->state != state_now);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
